-- SQL SCRIPT FOR GENERATING THE NECESARY TABLES ON THE SCHEMA --
CREATE TABLE EVENT_TYPES (ID SERIAL PRIMARY KEY, TYPE VARCHAR(20) NOT NULL);
CREATE TABLE SITE_TEMPLATES (ID SERIAL PRIMARY KEY, NAME VARCHAR(30) NOT NULL, EVENT_URL_TYPE VARCHAR(20) NOT NULL, CONTENT_TYPE INT NOT NULL DEFAULT 1, LINK VARCHAR(255) NOT NULL, DATE_FORMAT VARCHAR(30) NOT NULL, FOREIGN KEY(CONTENT_TYPE) REFERENCES EVENT_TYPES(ID));
CREATE TABLE ITEM_TEMPLATES (ID SERIAL PRIMARY KEY, NAME VARCHAR(30) NOT NULL, SITE_ID INT, FOREIGN KEY(SITE_ID) REFERENCES SITE_TEMPLATES(ID));
CREATE TABLE ITEM_CLASSES (ID SERIAL PRIMARY KEY, CLASS_NAME VARCHAR(30) NOT NULL, CLASS_TYPE VARCHAR(20) NOT NULL, VALUE_TYPE VARCHAR(20) NOT NULL, VALUE_LOCATION VARCHAR(30), PARENT_CLASS_ID INT, ITEM_ID INT, FOREIGN KEY(PARENT_CLASS_ID) REFERENCES ITEM_CLASSES(ID), FOREIGN KEY(ITEM_ID) REFERENCES ITEM_TEMPLATES(ID));
CREATE TABLE EVENTS (ID  SERIAL PRIMARY KEY, NAME VARCHAR(255)NOT NULL UNIQUE, TYPE_ID INT NOT NULL, IMAGE_URL VARCHAR(255), DATE_EVENT TIMESTAMP NOT NULL, ADDRESS VARCHAR(255) NOT NULL, PRICE VARCHAR(30), DESCRIPTION VARCHAR(255), LINK VARCHAR(255), SITE_ID INT, FOREIGN KEY(SITE_ID) REFERENCES SITE_TEMPLATES(ID), FOREIGN KEY(TYPE_ID) REFERENCES EVENT_TYPES(ID));
CREATE TABLE USERS (ID SERIAL PRIMARY KEY, EMAIL VARCHAR(255) NOT NULL UNIQUE, PASSWORD BYTEA NOT NULL, TYPE VARCHAR(20) NOT NULL DEFAULT 'NORMAL');
CREATE TABLE PLANS (ID SERIAL PRIMARY KEY, USER_ID INT, PLAN_DATE DATE NOT NULL, FOREIGN KEY(USER_ID) REFERENCES USERS(ID));
CREATE TABLE PLAN_EVENTS (PLAN_ID INT, EVENT_ID INT, PRIMARY KEY(PLAN_ID, EVENT_ID), FOREIGN KEY (PLAN_ID) REFERENCES PLANS(ID), FOREIGN KEY (EVENT_ID) REFERENCES EVENTS(ID));
CREATE TABLE ACCESS_LOGS (ID SERIAL PRIMARY KEY, USER_ID INT, TOKEN VARCHAR(255) NOT NULL, EXPIRATION_TIMESTAMP TIMESTAMP NOT NULL, FOREIGN KEY(USER_ID) REFERENCES USERS(ID));
CREATE TABLE PREFERENCES (USER_ID INT NOT NULL, EVENT_TYPE INT NOT NULL, PRIMARY KEY(USER_ID, EVENT_TYPE), FOREIGN KEY(USER_ID) REFERENCES USERS(ID), FOREIGN KEY(EVENT_TYPE) REFERENCES EVENT_TYPES(ID));
CREATE TABLE KEY_WORDS(ID SERIAL PRIMARY KEY, WORD VARCHAR(20) NOT NULL UNIQUE);
CREATE TABLE EVENT_TYPE_WORDS (EVENT_TYPE_ID INT, KEY_WORD_ID INT, PERCENTAGE DECIMAL(3,2) DEFAULT 0, FOREIGN KEY(EVENT_TYPE_ID) REFERENCES EVENT_TYPES(ID), FOREIGN KEY(KEY_WORD_ID) REFERENCES KEY_WORDS(ID), PRIMARY KEY(EVENT_TYPE_ID, KEY_WORD_ID)); 